    // TODO(port): distinguish G(L)->nilvalue sentinel from ordinary Nil for
    // exact parity with C's isvalid() check. For now, Nil returned from an
    // out-of-range index is treated as invalid.
    !matches!(val, LuaValue::Nil)
}

